// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





const getWeatherIcon = (condition: string | undefined) => {
  if (!condition) return '🌤️';
  switch (condition.toLowerCase()) {
    case 'sunny': return '☀️';
    case 'cloudy': return '☁️';
    case 'rainy': return '🌧️';
    case 'stormy': return '⛈️';
    case 'snowy': return '❄️';
    default: return '🌤️';
  }
};

const ForecastCard = (item: { day?: string; icon?: string; high?: number; low?: number }) => (
  <Card 
    as={Hoverable} 
    hoverStyle={{ transform: 'scale(1.02)', borderColor: 'var(--ggui-color-primary-400)' }}
    key={item.day} 
    padding="var(--ggui-spacing-3)" 
    border={true} 
    radius="md"
  >
    <Stack align="center" gap="var(--ggui-spacing-1)">
      <Text variant="label">{item.day}</Text>
      <Text size="2xl">{item.icon}</Text>
      <Row gap="var(--ggui-spacing-2)">
        <Text variant="bodySmall" weight="bold">{item.high}°</Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{item.low}°</Text>
      </Row>
    </Stack>
  </Card>
);


export default function Component(props: Props) {
  const [unitState, setUnitState] = useState(props.unit);

  const toggleUnit = () => setUnitState(prev => prev === 'C' ? 'F' : 'C');

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-8)" shadow="md" radius="lg">
          <Stack align="center" gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between" style={{ width: '100%' }}>
              <Heading level={1}>{props.city}</Heading>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
                <Button variant="ghost" size="sm" as={Clickable} onClick={() => window.location.reload()}>
                  <Icon name="refresh-cw" size={16} />
                </Button>
                <Button variant="outline" size="sm" as={Clickable} onClick={toggleUnit}>{unitState}</Button>
              </Stack>
            </Row>

            <Heading level={1} color="var(--ggui-color-primary-600)">{props.temperature}°{unitState}</Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{getWeatherIcon(props.condition)} {props.condition}</Text>

            <Row gap="var(--ggui-spacing-8)" justify="center">
              <Stack align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text weight="semibold">{props.humidity}%</Text>
              </Stack>
              <Stack align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
                <Text weight="semibold">{props.windSpeed} km/h</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>
        <Row gap="var(--ggui-spacing-3)" justify="center">
          {(props.forecast || []).map((day, idx) => (
            <ForecastCard 
              key={idx} 
              day={day.day} 
              icon={day.icon || getWeatherIcon(props.condition)} 
              high={day.high} 
              low={day.low} 
            />
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

