// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Helper components
const ProgressIndicator = (props: { current: number; total: number }) => (
  <Stack gap="var(--ggui-spacing-2)">
    <Text variant="overline">Step {props.current} of {props.total}</Text>
    <Progress value={(props.current / props.total) * 100} size="sm" />
  </Stack>
);

export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({ name: '', email: '', satisfaction: 3, features: [] as string[], comments: '' });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canProceed = useMemo(() => {
    if (step === 1) return data.name.trim() !== '' && validateEmail(data.email);
    return true;
  }, [step, data]);

  const submit = useAction<ActionSubmitPayload>('submit');

  const handleNext = () => setStep((s) => Math.min(s + 1, 5));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleSubmit = () => submit(data);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {step <= 4 && <ProgressIndicator current={step} total={4} />}

        <Card padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <>
                <Heading level={3}>Basic Information</Heading>
                <Input label="Name" required value={data.name} onChange={(v) => {
                  setData({ ...data, name: v });
                  setErrors({ ...errors, name: v.trim() === '' ? 'Name is required' : '' });
                }} error={errors.name} />
                <Input label="Email" type="email" required value={data.email} onChange={(v) => {
                  setData({ ...data, email: v });
                  setErrors({ ...errors, email: validateEmail(v) ? '' : 'Invalid email' });
                }} error={errors.email} />
              </>
            )}

            {step === 2 && (
              <>
                <Heading level={3}>Satisfaction Rating</Heading>
                <RadioGroup label="How satisfied are you?" value={data.satisfaction.toString()} onChange={(v) => setData({ ...data, satisfaction: parseInt(v) })} 
                  options={props.satisfactionLabels.map((l, i) => ({ value: (i + 1).toString(), label: l }))} />
              </>
            )}

            {step === 3 && (
              <>
                <Heading level={3}>Features of Interest</Heading>
                {props.featureOptions.map((f) => (
                  <Checkbox key={f} label={f} checked={data.features.includes(f)} onChange={(c) => setData({ ...data, features: c ? [...data.features, f] : data.features.filter((x) => x !== f) })} />
                ))}
              </>
            )}

            {step === 4 && (
              <>
                <Heading level={3}>Comments</Heading>
                <TextArea label="Comments" value={data.comments} onChange={(v) => setData({ ...data, comments: v })} maxLength={500} showCount />
              </>
            )}

            {step === 5 && (
              <>
                <Heading level={3}>Review</Heading>
                <Text>Name: {data.name}</Text>
                <Text>Email: {data.email}</Text>
                <Text>Satisfaction: {props.satisfactionLabels[data.satisfaction - 1] ?? 'Not rated'}</Text>
                <Text>Features: {data.features.join(', ')}</Text>
                <Text>Comments: {data.comments}</Text>
              </>
            )}

            <Row gap="var(--ggui-spacing-2)" justify="between">
              <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
              {step < 5 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canProceed}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>Submit</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

