            <Stack gap="var(--ggui-spacing-4)">
              {groupedMessages.map((group, i) => (
                <Stack key={i} align={group.sender === props.currentUser ? 'end' : 'start'} gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{group.sender}</Text>
                  {group.messages.map((msg, j) => (
                    <MessageBubble key={j} message={msg} isOwn={group.sender === props.currentUser} />
                  ))}
                </Stack>
              ))}
            </Stack>
          </Box>

          <Row gap="var(--ggui-spacing-2)">
            <FormField label="Message" style={{ flex: 1 }}>
              <Input
                value={inputText}
                onChange={setInputText}
                placeholder="Type a message..."
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              />
            </FormField>
            <Button variant="primary" onClick={handleSend} disabled={!inputText.trim()} aria-label="Send message">Send</Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

