      <Heading level={3}>Preferences</Heading>
      <Select label="Role" options={props.roleOptions.map((r) => ({ value: r, label: r }))} value={formData.role} onChange={(v) => setFormData({ ...formData, role: v })} />
      <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
      <Toggle label="Dark Mode" checked={formData.theme === 'dark'} onChange={(v) => setFormData({ ...formData, theme: v ? 'dark' : 'light' })} />
    </Stack>
  );

  const renderStep3 = () => (
    <Stack gap="var(--ggui-spacing-4)">
      <Heading level={3}>Review & Confirm</Heading>
      <Card padding="var(--ggui-spacing-4)" border={true}>
        <Stack gap="var(--ggui-spacing-2)">
          <Text><strong>Name:</strong> {formData.name}</Text>
          <Text><strong>Email:</strong> {formData.email}</Text>
          <Text><strong>Avatar:</strong> {formData.avatar}</Text>
          <Text><strong>Role:</strong> {formData.role}</Text>
          <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'On' : 'Off'}</Text>
          <Text><strong>Theme:</strong> {formData.theme}</Text>
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      {renderStepIndicator()}
      <Card padding="var(--ggui-spacing-6)" shadow="md">
        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {step === 3 && renderStep3()}
        <Spacer size={32} />
        <Row justify="between">
          <Button variant="ghost" disabled={step === 1} onClick={handleBack}>Go Back</Button>
          {step < 3 ? (
            <Button disabled={step === 1 && !isStep1Valid} onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Card>
    </Container>
  );
}
